<span class="line"><span style="color:#9399B2;">    &quot;</span><span style="color:#89B4FA;">cache_read_input_tokens</span><span style="color:#9399B2;">&quot;</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;"> 7000</span></span>
